# --- Query Depth Analysis ---
def calculate_query_depth(query_string):
    """Calculate the approximate depth of a GraphQL query by analyzing nesting."""
    depth = 0
    max_depth = 0
    for char in query_string:
        if char == '{':
            depth += 1
            max_depth = max(max_depth, depth)
        elif char == '}':
            depth -= 1
    return max_depth


def calculate_query_complexity(query_string):
    """Estimate query complexity based on field count."""
    # Count approximate number of fields requested
    # Remove string literals first
    cleaned = re.sub(r'"[^"]*"', '', query_string)
    # Count word tokens that look like field names (simple heuristic)
    fields = re.findall(r'[a-zA-Z_]\w*', cleaned)
    # Filter out known keywords
    keywords = {'query', 'mutation', 'subscription', 'fragment', 'on', 'true', 'false', 'null'}
    field_count = len([f for f in fields if f.lower() not in keywords])
    return field_count


def check_introspection_query(query_string):
    """Check if the query is an introspection query."""
    if query_string is None:
        return False
    introspection_fields = ['__schema', '__type', '__typename']
    # __typename is generally safe and used by clients; only block __schema and __type
    dangerous_introspection = ['__schema', '__type']
    for field in dangerous_introspection:
        if field in query_string:
            return True
    return False


# --- Security Middleware ---
def graphql_security_middleware(f):
    """Middleware to enforce query depth limits, complexity limits, and introspection controls."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if request.method == 'POST':
            data = request.get_json(silent=True)
            if data is None:
                return jsonify({"errors": [{"message": "Invalid JSON body"}]}), 400

            query = data.get('query', '')

            if not query or not isinstance(query, str):
                return jsonify({"errors": [{"message": "Query must be a non-empty string"}]}), 400

            # Check query size limit (prevent excessively large queries)
            if len(query) > 10000:
                return jsonify({"errors": [{"message": "Query too large. Maximum 10000 characters allowed."}]}), 400

            # Check introspection
            if not INTROSPECTION_ENABLED and check_introspection_query(query):
                return jsonify({
                    "errors": [{"message": "Introspection is disabled in this environment."}]
                }), 403

            # Check query depth
            depth = calculate_query_depth(query)
            if depth > MAX_QUERY_DEPTH:
                return jsonify({
                    "errors": [{"message": f"Query depth {depth} exceeds maximum allowed depth of {MAX_QUERY_DEPTH}."}]
                }), 400

            # Check query complexity
            complexity = calculate_query_complexity(query)
            if complexity > MAX_QUERY_COMPLEXITY:
                return jsonify({
                    "errors": [{"message": f"Query complexity {complexity} exceeds maximum allowed complexity of {MAX_QUERY_COMPLEXITY}."}]
                }), 400

        elif request.method == 'GET':
            query = request.args.get('query', '')

            if query and not isinstance(query, str):
                return jsonify({"errors": [{"message": "Query must be a string"}]}), 400

            if query and len(query) > 10000:
                return jsonify({"errors": [{"message": "Query too large."}]}), 400

            if not INTROSPECTION_ENABLED and check_introspection_query(query):
                return jsonify({
                    "errors": [{"message": "Introspection is disabled in this environment."}]
                }), 403

            depth = calculate_query_depth(query)
            if depth > MAX_QUERY_DEPTH:
                return jsonify({
                    "errors": [{"message": f"Query depth {depth} exceeds maximum allowed depth of {MAX_QUERY_DEPTH}."}]
                }), 400

        return f(*args, **kwargs)
    return decorated_function


